INSERT INTO conditions VALUES 
(1, 'chest_pain', 'https://medlineplus.gov/chestpain.html', 'Chest pain is discomfort or pressure in the chest area that may indicate serious cardiac, pulmonary, or gastrointestinal conditions.', 'Angina\nMyocardial infarction (heart attack)\nPneumonia\nPulmonary embolism\nPericarditis\nGastroesophageal reflux disease', 'Pressure-like pain\nTightness or squeezing sensation\nPain radiating to arm, jaw, neck, or back\nSweating\nNausea\nShortness of breath', 'Call emergency services immediately if you are experiencing pressure-like pain radiating to your arm or jaw, with sweating or nausea. Do not drive yourself to the hospital. For non-emergent chest discomfort, schedule a cardiology consultation within 24 to 48 hours.', 'This is a time-sensitive symptom. Early intervention significantly improves outcomes for cardiac events. Do not ignore chest pain or assume it will resolve on its own.', 'Educational information only. Consult a doctor for personal advice.'),
(2, 'breathing_difficulty', 'https://medlineplus.gov/breathingproblems.html', 'Respiratory distress or difficulty breathing is when you feel short of breath, which can indicate serious underlying conditions.', 'Asthma\nPneumonia\nPulmonary edema\nChronic obstructive pulmonary disease\nPulmonary embolism\nHeart failure', 'Shortness of breath\nWheezing\nRapid breathing\nChest tightness\nAir hunger\nInability to speak in full sentences\nBlue discoloration of lips or fingertips', 'Sit upright to ease breathing. Use your rescue inhaler if you have asthma and one is prescribed. Call emergency services immediately if symptoms are severe, worsening, or if your lips or fingertips turn blue.', 'Never ignore sudden onset breathing difficulty. Blue lips or fingertips indicate oxygen deprivation requiring immediate emergency care.', 'Educational information only. Consult a doctor for personal advice.'),
(3, 'cough', 'https://medlineplus.gov/cough.html', 'A cough is a reflex action to clear the airways of irritants, mucus, or foreign particles, which may be acute or chronic.', 'Viral infections (cold, flu, COVID-19)\nBacterial infections (pneumonia)\nAllergies\nAsthma\nPost-nasal drip\nGastroesophageal reflux\nChronic conditions like COPD', 'Dry or productive cough with mucus\nAssociated fever\nShortness of breath\nWheezing\nChest discomfort\nBlood in sputum', 'Stay well-hydrated with water and warm fluids. Use honey for throat soothing but avoid if you are diabetic. Consider over-the-counter expectorants for productive coughs. Seek medical care if cough persists beyond 3 weeks, worsens, or produces blood.', 'A cough lasting more than 3 weeks requires medical evaluation. Blood in sputum is never normal and needs immediate assessment.', 'Educational information only. Consult a doctor for personal advice.'),
(4, 'severe_headache', 'https://medlineplus.gov/headache.html', 'A sudden, severe headache (thunderclap headache) may indicate life-threatening neurological conditions requiring immediate evaluation.', 'Subarachnoid hemorrhage\nMeningitis\nEncephalitis\nCerebral venous thrombosis\nAcute glaucoma', 'Sudden onset of the worst headache of your life\nStiff neck\nFever\nConfusion\nSeizures\nVision changes\nWeakness\nLoss of consciousness', 'Proceed to the emergency department immediately. Do not take aspirin or other blood-thinning medications. Note the exact time of onset and any associated symptoms. Time-sensitive diagnosis is critical for optimal outcomes.', 'Sudden severe headache is a medical emergency. Do not attempt to sleep it off or wait for it to improve. Immediate evaluation can be life-saving.', 'Educational information only. Consult a doctor for personal advice.'),
(5, 'headache', 'https://medlineplus.gov/headache.html', 'A headache is pain or discomfort in the head, scalp, or neck, commonly caused by tension, migraines, or sinus issues.', 'Tension-type headaches\nMigraines\nCluster headaches\nSinus infections\nEye strain\nDehydration\nStress\nPoor sleep', 'Dull aching pain\nThrobbing or pulsating sensation\nPressure around forehead or temples\nSensitivity to light or sound\nNausea\nVisual disturbances', 'Rest in a quiet, dark room to reduce stimulation. Stay hydrated and maintain regular meals. Consider acetaminophen or ibuprofen if you have no contraindications. Apply a cold compress to your temples. Seek medical care if this is your first headache after age 50, the worst headache of your life, accompanied by weakness or vision changes, or persists beyond 72 hours despite treatment.', 'Most headaches are benign, but new or changing headache patterns warrant medical evaluation to rule out serious causes.', 'Educational information only. Consult a doctor for personal advice.'),
(6, 'neurological_deficit', 'https://medlineplus.gov/stroke.html', 'Acute neurological symptoms indicate potential stroke or other central nervous system emergencies requiring immediate intervention.', 'Ischemic or hemorrhagic stroke\nTransient ischemic attack\nSeizures\nBrain tumors\nMultiple sclerosis exacerbations', 'Facial drooping\nArm weakness or numbness\nSpeech difficulty (slurred or garbled)\nSudden vision loss\nSevere dizziness\nLoss of balance\nConfusion', 'Remember FAST: Face drooping, Arm weakness, Speech difficulty, Time to call 911 immediately. Do not wait to see if symptoms resolve. Note the exact time symptoms began which is critical for treatment decisions. Do not take aspirin until stroke type is determined.', 'Stroke treatment is time-critical. Every minute counts. Do not drive yourself to the hospital. Call emergency services for immediate transport.', 'Educational information only. Consult a doctor for personal advice.'),
(7, 'high_fever', 'https://medlineplus.gov/fever.html', 'A very high fever (hyperpyrexia) is an elevated body temperature above 103°F (39.4°C), potentially indicating serious infection or heat-related illness.', 'Severe bacterial or viral infections\nHeat stroke\nMalignant hyperthermia\nCentral nervous system disorders affecting temperature regulation', 'Temperature exceeding 103°F (39.4°C)\nConfusion\nAltered mental status\nStiff neck\nSevere headache\nRash\nSeizures\nHot dry skin (in heat stroke)', 'Verify temperature with a reliable thermometer. Hydrate with electrolyte solutions. Use tepid (not cold) sponging to reduce temperature. Seek urgent care immediately if temperature exceeds 104°F (40°C), or if accompanied by confusion, stiff neck, severe headache, or rash.', 'Very high fevers can cause brain damage or organ failure. Do not use ice baths or alcohol rubs. Seek emergency care for temperatures above 104°F.', 'Educational information only. Consult a doctor for personal advice.'),
(8, 'fever', 'https://medlineplus.gov/fever.html', 'Fever is an elevated body temperature above the normal range of 98.6°F (37°C), indicating the body\'s immune response to infection or inflammation.', 'Viral infections (cold, flu, COVID-19)\nBacterial infections\nInflammatory conditions\nVaccination responses', 'Elevated temperature between 100-102°F\nChills\nSweating\nHeadache\nBody aches\nFatigue\nLoss of appetite\nDehydration', 'Rest and drink plenty of fluids to prevent dehydration. Consider acetaminophen or ibuprofen for comfort and temperature reduction. Monitor your temperature every 4 to 6 hours. Schedule a medical appointment if fever persists beyond 3 days, exceeds 103°F (39.4°C), or is accompanied by severe headache, rash, or respiratory symptoms.', 'Fever in infants under 3 months (100.4°F or higher) requires immediate medical attention. Never give aspirin to children or teenagers with fever.', 'Educational information only. Consult a doctor for personal advice.'),
(9, 'covid', 'https://medlineplus.gov/covid19.html', 'COVID-19 is a respiratory illness caused by the SARS-CoV-2 virus, with symptoms ranging from mild to severe and potentially life-threatening.', 'Infection with the SARS-CoV-2 virus through respiratory droplets or aerosol transmission', 'Fever\nCough\nShortness of breath\nFatigue\nLoss of taste or smell\nSore throat\nBody aches\nHeadache\nGastrointestinal symptoms\nSevere cases: pneumonia or acute respiratory distress syndrome', 'Test with a rapid antigen or PCR test and isolate according to current CDC guidelines. Monitor oxygen levels with a pulse oximeter if available and seek care if below 92%. Rest, hydrate, and use acetaminophen or ibuprofen for fever and pain. Seek emergency care for difficulty breathing, persistent chest pain, confusion, or bluish lips. Contact your provider promptly to discuss antiviral treatment if you are at high risk.', 'High-risk individuals (elderly, immunocompromised, those with chronic conditions) should seek medical care early for potential antiviral treatment.', 'Educational information only. Consult a doctor for personal advice.'),
(10, 'flu', 'https://medlineplus.gov/flu.html', 'Influenza (flu) is a contagious respiratory illness caused by influenza viruses, typically more severe than the common cold.', 'Infection with influenza A or B viruses through respiratory droplets', 'Sudden onset fever\nBody aches\nHeadache\nChills\nFatigue\nCough\nSore throat\nRespiratory congestion', 'Rest extensively and maintain aggressive hydration. Use acetaminophen or ibuprofen for fever and muscle pain. Antiviral medications like oseltamivir or baloxavir are most effective within 48 hours of symptom onset, particularly for high-risk individuals. Seek care if symptoms worsen after initial improvement, you develop breathing difficulty, or fever persists beyond 3 days.', 'Flu can lead to serious complications like pneumonia. Annual vaccination is the best prevention. Antivirals work best when started early.', 'Educational information only. Consult a doctor for personal advice.'),
(11, 'severe_abdominal_pain', 'https://medlineplus.gov/abdominalpain.html', 'Severe abdominal pain may indicate life-threatening conditions requiring emergency surgical or medical intervention.', 'Appendicitis\nCholecystitis (gallbladder inflammation)\nIntestinal obstruction\nPerforated ulcer\nPancreatitis\nEctopic pregnancy', 'Sudden severe pain\nRigid or board-like abdomen\nPain localized to one area (especially lower right)\nVomiting blood\nBloody stools\nBlack tarry stools', 'Do not eat or drink anything. Do not take pain medications that could mask symptoms. Proceed to the emergency department immediately. Note the exact location and character of pain for medical evaluation.', 'Abdominal pain with vomiting blood or black stools indicates internal bleeding. A rigid abdomen suggests peritonitis. Both require immediate emergency care.', 'Educational information only. Consult a doctor for personal advice.'),
(12, 'abdominal_pain', 'https://medlineplus.gov/abdominalpain.html', 'Abdominal pain is discomfort or pain in the belly area, ranging from mild and temporary to severe and requiring medical attention.', 'Indigestion\nGastroenteritis\nConstipation\nGas\nIrritable bowel syndrome\nGastritis\nFood intolerance', 'Cramping\nBloating\nNausea\nLocalized or generalized pain\nChanges in bowel habits\nPain related to meals', 'Try a clear liquid diet for 12 to 24 hours, then gradually advance to bland foods (BRAT diet: bananas, rice, applesauce, toast). Avoid heavy, fatty, or spicy foods. Consider acetaminophen for pain but avoid NSAIDs if suspecting stomach issues. Seek medical care if pain persists beyond 24 hours, localizes to the lower right side, or is accompanied by fever, persistent vomiting, or inability to pass gas or stool.', 'Pain that localizes to the lower right abdomen may indicate appendicitis. Inability to pass gas with abdominal swelling suggests obstruction. Both require prompt evaluation.', 'Educational information only. Consult a doctor for personal advice.'),
(13, 'nausea', 'https://medlineplus.gov/nauseaandvomiting.html', 'Nausea and vomiting are symptoms of various conditions, ranging from minor infections to serious medical issues.', 'Viral gastroenteritis\nFood poisoning\nMedication side effects\nMotion sickness\nPregnancy\nMigraines\nGastrointestinal disorders', 'Queasiness\nRetching\nVomiting\nAbdominal discomfort\nWeakness\nSigns of dehydration (dark urine, dizziness, dry mouth)', 'Take small sips of clear liquids such as ginger tea, oral rehydration solutions, or electrolyte drinks. Gradually advance to bland foods (BRAT diet) as tolerated. Avoid fatty, spicy, or dairy foods until fully recovered. Seek care if vomiting persists beyond 24 hours, you show signs of dehydration, or you vomit blood or coffee-ground material.', 'Persistent vomiting can lead to dangerous dehydration. Vomiting blood or material resembling coffee grounds indicates bleeding and requires immediate care.', 'Educational information only. Consult a doctor for personal advice.'),
(14, 'back_pain', 'https://medlineplus.gov/backpain.html', 'Back pain is discomfort in the lower, middle, or upper back, most commonly musculoskeletal and self-limiting.', 'Muscle strain\nLigament sprain\nHerniated disc\nDegenerative disc disease\nSpinal stenosis\nOsteoarthritis\nOsteoporosis\nPoor posture', 'Dull ache\nSharp or stabbing pain\nMuscle spasms\nStiffness\nPain radiating to legs (sciatica)\nLimited range of motion', 'Apply ice for 15 to 20 minutes every 2 to 3 hours for the first 48 hours, then switch to heat therapy. Maintain light activity and avoid prolonged bed rest. Use acetaminophen or ibuprofen for pain relief. Practice good posture and ergonomic adjustments. Seek immediate care if you experience leg weakness, numbness in the groin area, loss of bladder or bowel control, or fever with back pain.', 'Back pain with loss of bowel or bladder control, or numbness in the saddle area, indicates cauda equina syndrome—a surgical emergency.', 'Educational information only. Consult a doctor for personal advice.'),
(15, 'joint_pain', 'https://medlineplus.gov/jointpain.html', 'Joint pain (arthralgia) is discomfort, pain, or inflammation in any of the body\'s joints.', 'Osteoarthritis\nRheumatoid arthritis\nGout\nBursitis\nTendinitis\nInjury\nOveruse\nAutoimmune conditions', 'Pain\nSwelling\nStiffness\nWarmth\nRedness\nLimited range of motion\nCreaking and clicking sounds with movement', 'Rest the affected joint and avoid aggravating activities. Apply ice for 15 to 20 minutes several times daily for acute pain, or heat for chronic stiffness. Consider acetaminophen or ibuprofen for pain and inflammation. Elevate the joint when possible to reduce swelling. Seek care if a single joint becomes red, warm, and severely painful (possible infection or gout), if you have morning stiffness lasting over 30 minutes, or if multiple joints are affected simultaneously.', 'A single hot, red, swollen joint requires urgent evaluation to rule out septic arthritis—a joint infection that can cause permanent damage if not treated promptly.', 'Educational information only. Consult a doctor for personal advice.'),
(16, 'injury', 'https://medlineplus.gov/woundsandinjuries.html', 'Acute injuries include sprains, strains, fractures, dislocations, cuts, and wounds requiring immediate first aid and possible medical evaluation.', 'Trauma\nFalls\nSports injuries\nAccidents\nOverexertion\nRepetitive stress', 'Pain\nSwelling\nBruising\nDeformity\nInability to bear weight\nLimited movement\nBleeding\nNumbness and tingling', 'Follow the PRICE protocol: Protect the area, Rest, Ice for 15 to 20 minutes every 2 to 3 hours, Compress with an elastic bandage, and Elevate above heart level. Avoid heat for the first 48 hours. Seek urgent care for suspected fractures, dislocations, deep wounds, uncontrolled bleeding, or numbness in the injured area. Ensure your tetanus vaccination is current for open wounds.', 'Numbness after an injury may indicate nerve damage. Deformity or inability to bear weight suggests fracture. Both require prompt medical evaluation.', 'Educational information only. Consult a doctor for personal advice.'),
(17, 'severe_rash', 'https://medlineplus.gov/rashes.html', 'A severe rash with systemic symptoms may indicate a serious drug reaction, infection, or dermatological emergency.', 'Severe drug reactions (Stevens-Johnson syndrome, toxic epidermal necrolysis)\nMeningococcemia\nSevere allergic reactions\nAutoimmune blistering diseases', 'Widespread rash with fever\nBlistering\nSkin peeling\nPainful skin\nRash involving mouth, eyes, or genitals\nPurple spots that don\'t blanch', 'Discontinue any non-essential medications immediately. Proceed to the emergency department immediately. Note any new medications started in the past month. Do not apply topical creams or ointments unless directed by medical personnel.', 'Rash with fever and purple non-blanching spots may indicate meningococcemia—a life-threatening bacterial infection requiring immediate antibiotics.', 'Educational information only. Consult a doctor for personal advice.'),
(18, 'rash', 'https://medlineplus.gov/rashes.html', 'A rash is a change in the skin\'s color, texture, or appearance, which may be localized or widespread.', 'Contact dermatitis\nAllergic reactions\nInfections (viral, bacterial, or fungal)\nEczema\nPsoriasis\nHeat rash\nInsect bites', 'Redness\nItching\nBumps\nBlisters\nScaling\nOozing\nSkin thickening', 'Avoid suspected irritants or allergens. Cleanse gently with fragrance-free, mild products. Apply moisturizer to maintain skin barrier. Use over-the-counter hydrocortisone cream (1% strength) for itchy, inflammatory rashes. Seek medical evaluation if the rash persists beyond one week, spreads rapidly, involves your face or genitals, or is accompanied by fever or pain.', 'Rapidly spreading rash with fever requires medical evaluation. Never ignore a rash that involves the eyes, mouth, or genitals.', 'Educational information only. Consult a doctor for personal advice.'),
(19, 'fatigue', 'https://medlineplus.gov/fatigue.html', 'Fatigue is persistent tiredness, exhaustion, or lack of energy not relieved by rest, potentially indicating underlying medical conditions.', 'Anemia\nThyroid dysfunction (hypothyroidism)\nSleep disorders (sleep apnea)\nDepression\nChronic fatigue syndrome\nDiabetes\nHeart disease\nMedication side effects', 'Persistent tiredness\nLack of motivation\nDifficulty concentrating\nMuscle weakness\nSleep that doesn\'t refresh', 'Prioritize 7 to 9 hours of quality sleep with consistent schedule. Maintain adequate hydration and balanced nutrition. Engage in regular light to moderate exercise. Limit caffeine and alcohol intake. Schedule a medical appointment if fatigue persists beyond 2 weeks, significantly impairs daily function, or is accompanied by weight change, fever, or shortness of breath.', 'Sudden severe fatigue with chest pain or shortness of breath may indicate cardiac issues. Fatigue with increased thirst and urination suggests diabetes.', 'Educational information only. Consult a doctor for personal advice.'),
(20, 'dizziness', 'https://medlineplus.gov/dizzinessandvertigo.html', 'Dizziness is a sensation of lightheadedness, unsteadiness, or vertigo (spinning sensation), with various potential causes.', 'Vertigo (BPPV, Meniere\'s disease, vestibular neuritis)\nOrthostatic hypotension\nDehydration\nAnemia\nHypoglycemia\nMedication side effects\nNeurological conditions', 'Spinning sensation\nLightheadedness\nImbalance\nNausea\nVomiting\nHeadache\nFainting episodes', 'Hydrate well with water and electrolytes. Rise slowly from sitting or lying positions. Avoid sudden head movements. For benign paroxysmal positional vertigo, the Epley maneuver may help. Avoid driving or operating machinery during episodes. Seek care if dizziness is accompanied by headache, weakness, speech difficulty, chest pain, or persistent vomiting.', 'Dizziness with chest pain, severe headache, or neurological symptoms requires emergency evaluation to rule out stroke or cardiac causes.', 'Educational information only. Consult a doctor for personal advice.'),
(21, 'allergy', 'https://medlineplus.gov/allergies.html', 'Allergic reactions range from mild, localized symptoms to severe, life-threatening anaphylaxis requiring immediate intervention.', 'Foods (peanuts, shellfish, eggs, milk)\nMedications (penicillin, sulfa drugs)\nInsect stings (bees, wasps)\nLatex\nEnvironmental triggers (pollen, dust mites)', 'Mild: Localized hives, itching, nasal congestion, sneezing\nSevere (anaphylaxis): Difficulty breathing, throat swelling, widespread hives with dizziness, rapid pulse, drop in blood pressure', 'Use your epinephrine auto-injector immediately for severe reactions if you have difficulty breathing, throat swelling, or widespread hives with dizziness. Call 911 immediately after epinephrine use, even if symptoms improve. For mild, localized symptoms, antihistamines may help, but monitor closely for progression to severe symptoms. Avoid known triggers and carry emergency medications if prescribed.', 'Anaphylaxis can progress rapidly. Always carry two epinephrine auto-injectors if prescribed. Antihistamines do not treat anaphylaxis—epinephrine is the only effective treatment.', 'Educational information only. Consult a doctor for personal advice.'),
(22, 'anxiety', 'https://medlineplus.gov/anxiety.html', 'Anxiety is a feeling of worry, nervousness, or unease, while panic attacks are sudden episodes of intense fear with physical symptoms.', 'Stress\nTrauma\nGenetic predisposition\nMedical conditions (thyroid disorders, heart arrhythmias)\nSubstance use\nCaffeine intake', 'Racing thoughts\nRestlessness\nRapid heartbeat\nSweating\nTrembling\nShortness of breath\nChest tightness\nFeeling of impending doom', 'Practice slow breathing: inhale for 4 seconds, hold for 7, exhale for 8. Use grounding techniques: identify 5 things you see, 4 you can touch, 3 you hear, 2 you smell, and 1 you taste. Reduce caffeine and alcohol intake. Maintain regular exercise and sleep schedules. Seek professional help if anxiety interferes with daily life, work, or relationships, or if panic attacks become frequent.', 'Chest pain with anxiety can mimic heart attack. If chest pain is new, severe, or accompanied by shortness of breath, seek emergency care to rule out cardiac causes.', 'Educational information only. Consult a doctor for personal advice.'),
(23, 'depression', 'https://medlineplus.gov/depression.html', 'Depression is a common but serious mood disorder affecting how you feel, think, and handle daily activities.', 'Genetic, biological, environmental, and psychological factors\nTrauma\nStress\nMedical conditions\nCertain medications', 'Persistent sadness\nLoss of interest in activities\nChanges in appetite or sleep\nFatigue\nFeelings of worthlessness\nDifficulty concentrating\nThoughts of death or suicide', 'Call 988 (Suicide and Crisis Lifeline) or call 911 immediately if you have thoughts of self-harm or suicide. Psychotherapy (CBT or interpersonal therapy) and antidepressant medications are effective treatments. Maintain social connections and regular sleep schedules. Engage in physical activity and outdoor exposure. Schedule an appointment with a healthcare provider or mental health professional to discuss treatment options.', 'Suicidal thoughts are a medical emergency. You are not alone—help is available 24/7. Reach out to a trusted person or call 988 immediately.', 'Educational information only. Consult a doctor for personal advice.'),
(24, 'general_symptom', NULL, 'I couldn\'t recognize that specific condition in my database.', 'Condition not in current database\nTypo or unclear description\nRare or complex medical condition requiring professional evaluation', 'Unable to determine without more specific information.', 'You can ask about common symptoms such as headache, fever, cough, chest pain, stomach pain, or dizziness. I can provide general health guidance and educational information, and I can also direct you to appropriate medical resources.', 'When in doubt about symptoms, especially if they are severe, worsening, or causing significant concern, consult a healthcare professional promptly.', 'Educational information only. Consult a doctor for personal advice.');
